import React, { useState, useEffect, useCallback } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import {
  LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip,
  Legend, ResponsiveContainer,
} from 'recharts';
import { toJalaali } from 'jalaali-js';
import api from '../services/api';
import ErrorBoundary from './ErrorBoundary';
import MeasurementPanel from './MeasurementPanel';
import ReportModal from './ReportModal';

// ─── Jalali helpers ────────────────────────────────────────────────────────────
const JALALI_MONTHS = [
  'فروردین','اردیبهشت','خرداد','تیر','مرداد','شهریور',
  'مهر','آبان','آذر','دی','بهمن','اسفند',
];

function toJalaliDate(isoStr) {
  try {
    const d = new Date(isoStr);
    const { jy, jm, jd } = jalaali.toJalaali(d.getFullYear(), d.getMonth() + 1, d.getDate());
    return `${jd} ${JALALI_MONTHS[jm - 1]} ${jy}`;
  } catch {
    return isoStr;
  }
}

function toJalaliShort(isoStr) {
  try {
    const d = new Date(isoStr);
    const { jy, jm, jd } = jalaali.toJalaali(d.getFullYear(), d.getMonth() + 1, d.getDate());
    return `${jy}/${String(jm).padStart(2,'0')}/${String(jd).padStart(2,'0')}`;
  } catch {
    return isoStr;
  }
}

// ─── Patient edit modal ────────────────────────────────────────────────────────
function EditPatientModal({ patient, onClose, onSaved }) {
  const [form, setForm] = useState({ ...patient });
  const [error, setError] = useState('');
  const [saving, setSaving] = useState(false);

  const handleSubmit = async (e) => {
    e.preventDefault();
    setSaving(true);
    try {
      const res = await api.put(`/patients/${patient.id}`, form);
      onSaved(res.data);
      onClose();
    } catch (err) {
      setError(err.response?.data?.error || 'Update failed.');
    } finally {
      setSaving(false);
    }
  };

  return (
    <div className="modal-overlay" onClick={onClose}>
      <div className="modal" onClick={e => e.stopPropagation()}>
        <div className="modal-header">
          <h2>ویرایش اطلاعات بیمار</h2>
          <button className="modal-close" onClick={onClose}>×</button>
        </div>
        <div className="modal-body">
          {error && <div className="alert alert-error">{error}</div>}
          <form id="edit-patient-form" onSubmit={handleSubmit}>
            <div className="form-group">
              <label className="form-label">نام کامل</label>
              <input className="form-input" value={form.name}
                onChange={e => setForm(f => ({ ...f, name: e.target.value }))} required />
            </div>
            <div className="form-row">
              <div className="form-group">
                <label className="form-label">قد (cm)</label>
                <input className="form-input" type="number" value={form.height_cm}
                  onChange={e => setForm(f => ({ ...f, height_cm: e.target.value }))} required />
              </div>
              <div className="form-group">
                <label className="form-label">سن</label>
                <input className="form-input" type="number" value={form.age}
                  onChange={e => setForm(f => ({ ...f, age: e.target.value }))} required />
              </div>
            </div>
            <div className="form-group">
              <label className="form-label">جنسیت</label>
              <select className="form-select" value={form.is_male ? 'male' : 'female'}
                onChange={e => setForm(f => ({ ...f, is_male: e.target.value === 'male' }))}>
                <option value="male">مرد</option>
                <option value="female">زن</option>
              </select>
            </div>
            <div className="form-group">
              <label className="form-label">شناسه چت بله</label>
              <input className="form-input" value={form.bale_chat_id || ''}
                onChange={e => setForm(f => ({ ...f, bale_chat_id: e.target.value }))}
                placeholder="اختیاری" />
            </div>
          </form>
        </div>
        <div className="modal-footer">
          <button className="btn btn-ghost" onClick={onClose}>انصراف</button>
          <button className="btn btn-primary" form="edit-patient-form" type="submit" disabled={saving}>
            {saving ? <><span className="spinner" /> در حال ذخیره…</> : 'ذخیره تغییرات'}
          </button>
        </div>
      </div>
    </div>
  );
}

// ─── Measurement edit modal ────────────────────────────────────────────────────
function EditMeasurementModal({ measurement, onClose, onSaved, onDeleted }) {
  const [form, setForm] = useState({
    weight:       measurement.weight ?? '',
    body_fat_pct: measurement.body_fat_pct ?? '',
    fat_mass:     measurement.fat_mass ?? '',
    muscle_mass:  measurement.muscle_mass ?? '',
    water_kg:     measurement.water_kg ?? '',
    notes:        measurement.notes ?? '',
  });
  const [saving, setSaving]   = useState(false);
  const [deleting, setDeleting] = useState(false);
  const [error, setError]     = useState('');
  const [confirmDel, setConfirmDel] = useState(false);

  const handleSave = async (e) => {
    e.preventDefault();
    setSaving(true);
    try {
      const res = await api.put(
        `/patients/${measurement.patient_id}/measurements/${measurement.id}`,
        form,
      );
      onSaved(res.data);
      onClose();
    } catch (err) {
      setError(err.response?.data?.error || 'ذخیره ناموفق بود.');
    } finally {
      setSaving(false);
    }
  };

  const handleDelete = async () => {
    setDeleting(true);
    try {
      await api.delete(
        `/patients/${measurement.patient_id}/measurements/${measurement.id}`,
      );
      onDeleted(measurement.id);
      onClose();
    } catch (err) {
      setError(err.response?.data?.error || 'حذف ناموفق بود.');
      setDeleting(false);
    }
  };

  const Field = ({ label, fkey, step = '0.1' }) => (
    <div className="form-group">
      <label className="form-label">{label}</label>
      <input className="form-input" type="number" step={step} value={form[fkey]}
        onChange={e => setForm(f => ({ ...f, [fkey]: e.target.value }))} />
    </div>
  );

  return (
    <div className="modal-overlay" onClick={onClose}>
      <div className="modal" onClick={e => e.stopPropagation()}>
        <div className="modal-header">
          <h2>ویرایش اندازه‌گیری</h2>
          <button className="modal-close" onClick={onClose}>×</button>
        </div>
        <div className="modal-body">
          {error && <div className="alert alert-error">{error}</div>}
          <div style={{ background: '#ebf8ff', padding: '8px 14px', borderRadius: 8,
            marginBottom: 14, fontSize: 13, color: '#2b6cb0', fontWeight: 600 }}>
            📅 تاریخ اندازه‌گیری: {toJalaliDate(measurement.recorded_at)}
          </div>
          <form id="edit-m-form" onSubmit={handleSave}>
            <div className="form-row">
              <div className="form-group">
                <label className="form-label">وزن (kg) *</label>
                <input className="form-input" type="number" step="0.1" required
                  value={form.weight}
                  onChange={e => setForm(f => ({ ...f, weight: e.target.value }))} />
              </div>
              <Field label="درصد چربی (%)" fkey="body_fat_pct" />
            </div>
            <div className="form-row">
              <Field label="توده چربی (kg)" fkey="fat_mass" />
              <Field label="عضله (kg)" fkey="muscle_mass" />
            </div>
            <div className="form-row">
              <Field label="آب بدن (kg)" fkey="water_kg" />
              <div className="form-group">
                <label className="form-label">یادداشت</label>
                <input className="form-input" value={form.notes}
                  onChange={e => setForm(f => ({ ...f, notes: e.target.value }))} />
              </div>
            </div>
          </form>
        </div>
        <div className="modal-footer" style={{ justifyContent: 'space-between' }}>
          <button className="btn btn-sm" style={{ background: '#fff5f5', color: '#c53030',
            border: '1px solid #fc8181' }} onClick={() => setConfirmDel(true)}>
            🗑 حذف
          </button>
          <div style={{ display: 'flex', gap: 8 }}>
            <button className="btn btn-ghost" onClick={onClose}>انصراف</button>
            <button className="btn btn-primary" form="edit-m-form" type="submit" disabled={saving}>
              {saving ? <><span className="spinner" /> ذخیره…</> : 'ذخیره'}
            </button>
          </div>
        </div>
        {confirmDel && (
          <div style={{ padding: '12px 20px', background: '#fff5f5',
            borderTop: '2px solid #fc8181', borderRadius: '0 0 var(--radius) var(--radius)' }}>
            <p style={{ color: '#c53030', marginBottom: 10, fontWeight: 600 }}>
              ⚠ آیا از حذف این اندازه‌گیری مطمئن هستید؟
            </p>
            <div style={{ display: 'flex', gap: 8 }}>
              <button className="btn btn-ghost btn-sm" onClick={() => setConfirmDel(false)}>
                انصراف
              </button>
              <button className="btn btn-sm" disabled={deleting}
                style={{ background: '#c53030', color: '#fff' }}
                onClick={handleDelete}>
                {deleting ? 'در حال حذف…' : 'بله، حذف شود'}
              </button>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

// ─── Export menu ───────────────────────────────────────────────────────────────
function ExportMenu({ patientId }) {
  const [open, setOpen] = useState(false);
  const download = (fmt) => {
    const token = localStorage.getItem('jwt_token');
    const url = `/api/patients/${patientId}/export?format=${fmt}`;
    const a = document.createElement('a');
    a.href = url;
    a.setAttribute('download', '');
    document.body.appendChild(a);
    fetch(url, { headers: { Authorization: `Bearer ${token}` } })
      .then(r => r.blob())
      .then(blob => {
        const burl = URL.createObjectURL(blob);
        a.href = burl;
        a.click();
        URL.revokeObjectURL(burl);
        document.body.removeChild(a);
      });
    setOpen(false);
  };
  return (
    <div style={{ position: 'relative' }}>
      <button className="btn btn-ghost" onClick={() => setOpen(v => !v)}>📥 خروجی ▾</button>
      {open && (
        <div style={{ position: 'absolute', top: '100%', right: 0, background: '#fff',
          border: '1px solid var(--gray-200)', borderRadius: 'var(--radius)',
          boxShadow: 'var(--shadow-md)', zIndex: 10, minWidth: 140 }}>
          <button className="btn btn-ghost"
            style={{ width: '100%', justifyContent: 'flex-start', borderRadius: 0 }}
            onClick={() => download('csv')}>📄 CSV</button>
          <button className="btn btn-ghost"
            style={{ width: '100%', justifyContent: 'flex-start', borderRadius: 0 }}
            onClick={() => download('excel')}>📊 Excel</button>
        </div>
      )}
    </div>
  );
}

// ─── Chart config ──────────────────────────────────────────────────────────────
const CHART_LINES = [
  { key: 'weight',       name: 'وزن (kg)',      color: '#2b6cb0', yAxis: 'left'  },
  { key: 'body_fat_pct', name: 'درصد چربی (%)', color: '#e53e3e', yAxis: 'right' },
  { key: 'muscle_mass',  name: 'عضله (kg)',     color: '#38a169', yAxis: 'left'  },
  { key: 'water_kg',     name: 'آب بدن (kg)',   color: '#3182ce', yAxis: 'left'  },
];

// ─── Main component ────────────────────────────────────────────────────────────
export default function PatientProfile({ socket }) {
  const { id } = useParams();
  const navigate = useNavigate();
  const [patient, setPatient]           = useState(null);
  const [measurements, setMeasurements] = useState([]);
  const [loading, setLoading]           = useState(true);
  const [tab, setTab]                   = useState('overview');
  const [showEdit, setShowEdit]         = useState(false);
  const [showReport, setShowReport]     = useState(false);
  const [editingM, setEditingM]         = useState(null);
  const [selectedMetrics, setSelectedMetrics] = useState({
    weight: true, body_fat_pct: true, muscle_mass: false, water_kg: false,
  });

  const load = useCallback(async () => {
    try {
      const [pRes, mRes] = await Promise.all([
        api.get(`/patients/${id}`),
        api.get(`/patients/${id}/measurements`),
      ]);
      setPatient(pRes.data);
      setMeasurements(mRes.data);
    } catch {
      navigate('/patients');
    } finally {
      setLoading(false);
    }
  }, [id, navigate]);

  useEffect(() => { load(); }, [load]);

  const onNewMeasurement = (m) => setMeasurements(prev => [...prev, m]);

  const onMeasurementSaved = (updated) =>
    setMeasurements(prev => prev.map(m => m.id === updated.id ? updated : m));

  const onMeasurementDeleted = (mid) =>
    setMeasurements(prev => prev.filter(m => m.id !== mid));

  if (loading) return <div className="flex-center" style={{ height: 300 }}><span className="spinner" /></div>;
  if (!patient) return null;

  const chartData = measurements.map(m => ({
    date: toJalaliShort(m.recorded_at),
    weight:       m.weight,
    body_fat_pct: m.body_fat_pct,
    muscle_mass:  m.muscle_mass,
    water_kg:     m.water_kg,
  }));

  const firstW = measurements[0]?.weight;
  const lastW  = measurements[measurements.length - 1]?.weight;
  const totalLoss = firstW && lastW ? (firstW - lastW).toFixed(1) : null;
  const firstDate  = measurements[0]?.recorded_at;
  const lastDate   = measurements[measurements.length - 1]?.recorded_at;

  return (
    <ErrorBoundary>
      {showEdit && (
        <EditPatientModal
          patient={patient}
          onClose={() => setShowEdit(false)}
          onSaved={(p) => setPatient(p)}
        />
      )}
      {showReport && (
        <ReportModal
          patient={patient}
          measurements={measurements}
          onClose={() => setShowReport(false)}
        />
      )}
      {editingM && (
        <EditMeasurementModal
          measurement={editingM}
          onClose={() => setEditingM(null)}
          onSaved={onMeasurementSaved}
          onDeleted={onMeasurementDeleted}
        />
      )}

      {/* Header card */}
      <div className="card mb-20">
        <div className="flex-between">
          <div style={{ display: 'flex', alignItems: 'center', gap: 16 }}>
            <button className="btn btn-ghost btn-sm" onClick={() => navigate('/patients')}>← بازگشت</button>
            <div>
              <h2 style={{ fontSize: 20, fontWeight: 700 }}>{patient.name}</h2>
              <span className="text-muted" style={{ fontSize: 13 }}>
                {patient.age} سال ·{' '}
                {patient.height_cm} cm ·{' '}
                {patient.is_male ? 'مرد' : 'زن'}
                {patient.bale_chat_id && <> · 📲 بله متصل</>}
              </span>
            </div>
          </div>
          <div style={{ display: 'flex', gap: 8 }}>
            <ExportMenu patientId={patient.id} />
            <button className="btn btn-ghost" onClick={() => setShowEdit(true)}>✏️ ویرایش</button>
            <button className="btn btn-primary" onClick={() => setShowReport(true)}>
              📊 گزارش و ارسال
            </button>
          </div>
        </div>

        {totalLoss !== null && (
          <div style={{ marginTop: 16, display: 'flex', gap: 28, flexWrap: 'wrap' }}>
            <div>
              <span className="text-muted">وزن اولیه:</span>{' '}
              <strong>{firstW} kg</strong>
              {firstDate && <span className="text-muted" style={{ fontSize: 12 }}> ({toJalaliDate(firstDate)})</span>}
            </div>
            <div>
              <span className="text-muted">وزن فعلی:</span>{' '}
              <strong>{lastW} kg</strong>
              {lastDate && <span className="text-muted" style={{ fontSize: 12 }}> ({toJalaliDate(lastDate)})</span>}
            </div>
            <div>
              <span className="text-muted">تغییر کل:</span>{' '}
              <strong style={{ color: parseFloat(totalLoss) > 0 ? 'var(--green)' : 'var(--red)' }}>
                {parseFloat(totalLoss) > 0 ? '−' : '+'}{Math.abs(totalLoss)} kg
              </strong>
            </div>
            <div>
              <span className="text-muted">تعداد ویزیت‌ها:</span>{' '}
              <strong>{measurements.length}</strong>
            </div>
          </div>
        )}
      </div>

      {/* Tabs */}
      <div className="tabs">
        {['overview', 'measure', 'history'].map(t => (
          <button key={t} className={`tab-btn ${tab === t ? 'active' : ''}`} onClick={() => setTab(t)}>
            {{ overview: '📊 نمودار', measure: '⚖️ اندازه‌گیری', history: '📋 تاریخچه' }[t]}
          </button>
        ))}
      </div>

      {/* Overview tab */}
      {tab === 'overview' && (
        measurements.length < 2 ? (
          <div className="card">
            <div className="empty-state">
              <div className="empty-state-icon">📊</div>
              <h3>داده کافی وجود ندارد</h3>
              <p>حداقل ۲ اندازه‌گیری برای نمایش نمودار لازم است.</p>
              <button className="btn btn-primary mt-12" onClick={() => setTab('measure')}>
                اولین اندازه‌گیری را ثبت کنید
              </button>
            </div>
          </div>
        ) : (
          <div className="card">
            <div className="flex-between mb-16">
              <span className="card-title" style={{ marginBottom: 0 }}>نمودار پیشرفت</span>
              <div style={{ display: 'flex', gap: 10, flexWrap: 'wrap' }}>
                {CHART_LINES.map(l => (
                  <label key={l.key} className="checkbox-label">
                    <input type="checkbox" checked={selectedMetrics[l.key]}
                      onChange={e => setSelectedMetrics(prev => ({ ...prev, [l.key]: e.target.checked }))} />
                    <span style={{ color: l.color, fontFamily: 'Tahoma, sans-serif' }}>{l.name}</span>
                  </label>
                ))}
              </div>
            </div>
            <div className="chart-container">
              <ResponsiveContainer width="100%" height="100%">
                <LineChart data={chartData} margin={{ top: 5, right: 20, left: 0, bottom: 5 }}>
                  <CartesianGrid strokeDasharray="3 3" stroke="var(--gray-200)" />
                  <XAxis dataKey="date" tick={{ fontSize: 11 }} />
                  <YAxis yAxisId="left" tick={{ fontSize: 11 }} />
                  <YAxis yAxisId="right" orientation="right" tick={{ fontSize: 11 }} />
                  <Tooltip />
                  <Legend formatter={(value) => (
                    <span style={{ fontFamily: 'Tahoma, sans-serif', fontSize: 12 }}>{value}</span>
                  )} />
                  {CHART_LINES.filter(l => selectedMetrics[l.key]).map(l => (
                    <Line key={l.key} yAxisId={l.yAxis} type="monotone" dataKey={l.key}
                      name={l.name} stroke={l.color} strokeWidth={2}
                      dot={{ r: 4 }} activeDot={{ r: 6 }} connectNulls />
                  ))}
                </LineChart>
              </ResponsiveContainer>
            </div>
          </div>
        )
      )}

      {/* Measure tab */}
      {tab === 'measure' && (
        <MeasurementPanel patient={patient} socket={socket} onMeasurementReady={onNewMeasurement} />
      )}

      {/* History tab */}
      {tab === 'history' && (
        <div className="card">
          <div className="card-title">تاریخچه اندازه‌گیری‌ها</div>
          {measurements.length === 0 ? (
            <div className="empty-state" style={{ padding: '30px 0' }}>
              <p>هنوز اندازه‌گیری ثبت نشده است.</p>
            </div>
          ) : (
            <div className="table-wrapper">
              <table>
                <thead>
                  <tr>
                    <th>تاریخ</th>
                    <th>وزن (kg)</th>
                    <th>چربی (%)</th>
                    <th>توده چربی (kg)</th>
                    <th>عضله (kg)</th>
                    <th>آب (kg)</th>
                    <th>یادداشت</th>
                    <th></th>
                  </tr>
                </thead>
                <tbody>
                  {[...measurements].reverse().map(m => (
                    <tr key={m.id}>
                      <td style={{ whiteSpace: 'nowrap', fontFamily: 'Tahoma, sans-serif' }}>
                        {toJalaliDate(m.recorded_at)}
                      </td>
                      <td><strong>{m.weight}</strong></td>
                      <td>{m.body_fat_pct ?? '—'}</td>
                      <td>{m.fat_mass ?? '—'}</td>
                      <td>{m.muscle_mass ?? '—'}</td>
                      <td>{m.water_kg ?? '—'}</td>
                      <td className="text-muted">{m.notes || '—'}</td>
                      <td>
                        <button className="btn btn-ghost btn-sm"
                          style={{ padding: '2px 8px', fontSize: 13 }}
                          onClick={() => setEditingM(m)}>
                          ✏️
                        </button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}
        </div>
      )}
    </ErrorBoundary>
  );
}
